     1→import {
     2→  BadRequestException,
     3→  Injectable,
     4→  Logger,
     5→  NotFoundException,
     6→} from '@nestjs/common';
     7→import { ConfigService } from '@nestjs/config';
     8→import { TransactionHost } from '@nestjs-cls/transactional';
     9→
    10→import {
    11→  WithdrawalMethodType,
    12→  WithdrawalRequestEntity,
    13→  WithdrawalRequestStatus,
    14→} from '@/db';
    15→import { TransactionalAdapterTypeOrm } from '@/modules/global';
    16→
    17→import {
    18→  NOWPaymentsService,
    19→  PayoutCreateResponse,
    20→  PayoutRequest,
    21→  PayoutResponse,
    22→} from './nowpayments.service';
    23→
    24→/**
    25→ * Service for managing NOWPayments Payouts (Withdrawals).
    26→ * Handles creation of payouts for crypto withdrawals via NOWPayments.
    27→ *
    28→ * Supports CRYPTO and NOWPAYMENTS withdrawal method types (SavedCryptoAddressEntity).
    29→ */
    30→@Injectable()
    31→export class NOWPaymentsPayoutsService {
    32→  private readonly logger = new Logger(NOWPaymentsPayoutsService.name);
    33→
    34→  constructor(
    35→    private readonly nowpaymentsService: NOWPaymentsService,
    36→    private readonly configService: ConfigService,
    37→    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
    38→  ) {}
    39→
    40→  /**
    41→   * Create a NOWPayments payout (withdrawal).
    42→   * Converts a withdrawal request to a NOWPayments payout.
    43→   *
    44→   * @param withdrawalRequest - Withdrawal request entity
    45→   * @returns Payout response with payout ID and status
    46→   */
    47→  async createPayout(
    48→    withdrawalRequest: WithdrawalRequestEntity,
    49→  ): Promise<PayoutCreateResponse> {
    50→    if (
    51→      withdrawalRequest.withdrawalMethodType !== WithdrawalMethodType.Crypto &&
    52→      withdrawalRequest.withdrawalMethodType !==
    53→        WithdrawalMethodType.NowPayments
    54→    ) {
    55→      throw new BadRequestException(
    56→        `Withdrawal method must be CRYPTO or NOWPAYMENTS for NOWPayments payout, got: ${withdrawalRequest.withdrawalMethodType}`,
    57→      );
    58→    }
    59→
    60→    if (
    61→      !withdrawalRequest.cryptoPaymentMethod ||
    62→      !withdrawalRequest.cryptoPaymentMethod.address
    63→    ) {
    64→      throw new BadRequestException(
    65→        'Withdrawal request does not have a valid crypto address',
    66→      );
    67→    }
    68→
    69→    const currency = 'usdttrc20';
    70→
    71→    const amount = withdrawalRequest.amount / 100;
    72→
    73→    const nowpaymentsIpnUrl = this.configService.get<string>(
    74→      'NOWPAYMENTS_IPN_URL',
    75→    );
    76→    const ipnCallbackUrl = nowpaymentsIpnUrl
    77→      ? `${nowpaymentsIpnUrl}/internal/nowpayments-webhook`
    78→      : undefined;
    79→
    80→    this.logger.log(
    81→      `Creating NOWPayments payout for withdrawal ${withdrawalRequest.id}: ${amount} ${currency} to ${withdrawalRequest.cryptoPaymentMethod.address}`,
    82→    );
    83→
    84→    const payoutRequest: PayoutRequest = {
    85→      ipn_callback_url: ipnCallbackUrl,
    86→      withdrawals: [
    87→        {
    88→          address: withdrawalRequest.cryptoPaymentMethod.address,
    89→          amount,
    90→          currency,
    91→          ipn_callback_url: ipnCallbackUrl,
    92→        },
    93→      ],
    94→    };
    95→
    96→    const payout = await this.nowpaymentsService.createPayout(payoutRequest);
    97→
    98→    this.logger.log(
    99→      `Created NOWPayments Payout: ${payout.id} for withdrawal: ${withdrawalRequest.id}`,
   100→    );
   101→
   102→    return payout;
   103→  }
   104→
   105→  /**
   106→   * Get payout status from NOWPayments.
   107→   * Used to check the status of a withdrawal payout.
   108→   *
   109→   * @param withdrawalRequestId - Withdrawal request ID
   110→   * @returns Payout status and details
   111→   */
   112→  async getPayoutStatus(withdrawalRequestId: string): Promise<PayoutResponse> {
   113→    return this.txHost.withTransaction(async () => {
   114→      const withdrawalRepository = this.txHost.tx.getRepository(
   115→        WithdrawalRequestEntity,
   116→      );
   117→
   118→      const withdrawal = await withdrawalRepository.findOne({
   119→        where: { id: withdrawalRequestId },
   120→      });
   121→
   122→      if (!withdrawal) {
   123→        throw new NotFoundException('Withdrawal request not found');
   124→      }
   125→
   126→      const confirmationText = withdrawal.confirmationText || '';
   127→      const match = confirmationText.match(/NOWPayments Payout ID: (\d+)/);
   128→      const payoutId = match ? parseInt(match[1], 10) : null;
   129→
   130→      if (!payoutId) {
   131→        throw new BadRequestException(
   132→          'Withdrawal does not have NOWPayments payout reference',
   133→        );
   134→      }
   135→
   136→      const payout = await this.nowpaymentsService.getPayout(payoutId);
   137→
   138→      return payout;
   139→    });
   140→  }
   141→
   142→  /**
   143→   * Handle payout success webhook event.
   144→   * Called when NOWPayments confirms successful payout.
   145→   *
   146→   * @param payoutId - NOWPayments payout ID
   147→   * @param transactionHash - Blockchain transaction hash
   148→   * @returns Updated withdrawal request
   149→   */
   150→  async handlePayoutSuccess(
   151→    payoutId: number,
   152→    transactionHash?: string,
   153→  ): Promise<WithdrawalRequestEntity> {
   154→    return this.txHost.withTransaction(async () => {
   155→      const withdrawalRepository = this.txHost.tx.getRepository(
   156→        WithdrawalRequestEntity,
   157→      );
   158→
   159→      const withdrawal = await withdrawalRepository.findOne({
   160→        where: { nowpaymentsPayoutId: payoutId },
   161→      });
   162→
   163→      if (!withdrawal) {
   164→        this.logger.warn(
   165→          `No withdrawal found for NOWPayments payout: ${payoutId}`,
   166→        );
   167→        throw new NotFoundException(
   168→          `Withdrawal not found for payout ${payoutId}`,
   169→        );
   170→      }
   171→
   172→      if (transactionHash) {
   173→        const currentText =
   174→          withdrawal.confirmationText || `NOWPayments Payout ID: ${payoutId}`;
   175→        withdrawal.confirmationText = `${currentText}\nTransaction Hash: ${transactionHash}`;
   176→      }
   177→
   178→      await withdrawalRepository.save(withdrawal);
   179→
   180→      this.logger.log(
   181→        `✓ Payout success for withdrawal: ${withdrawal.id} (hash: ${transactionHash || 'unknown'})`,
   182→      );
   183→
   184→      return withdrawal;
   185→    });
   186→  }
   187→
   188→  /**
   189→   * Handle payout failure webhook event.
   190→   * Called when NOWPayments payout fails.
   191→   *
   192→   * @param payoutId - NOWPayments payout ID
   193→   * @param reason - Optional failure reason
   194→   * @returns Updated withdrawal request
   195→   */
   196→  async handlePayoutFailure(
   197→    payoutId: number,
   198→    reason?: string,
   199→  ): Promise<WithdrawalRequestEntity> {
   200→    return this.txHost.withTransaction(async () => {
   201→      const withdrawalRepository = this.txHost.tx.getRepository(
   202→        WithdrawalRequestEntity,
   203→      );
   204→
   205→      // Find withdrawal by payout ID
   206→      const withdrawal = await withdrawalRepository.findOne({
   207→        where: { nowpaymentsPayoutId: payoutId },
   208→      });
   209→
   210→      if (!withdrawal) {
   211→        this.logger.warn(
   212→          `No withdrawal found for NOWPayments payout: ${payoutId}`,
   213→        );
   214→        throw new NotFoundException(
   215→          `Withdrawal not found for payout ${payoutId}`,
   216→        );
   217→      }
   218→
   219→      withdrawal.status = WithdrawalRequestStatus.Approved;
   220→      withdrawal.rejectionReason = reason || 'NOWPayments payout failed';
   221→      withdrawal.nowpaymentsPayoutId = null;
   222→
   223→      await withdrawalRepository.save(withdrawal);
   224→
   225→      this.logger.log(
   226→        `✗ Payout failed for withdrawal: ${withdrawal.id} (reason: ${reason || 'unknown'})`,
   227→      );
   228→
   229→      return withdrawal;
   230→    });
   231→  }
   232→}
