    28→  WithdrawalMethodType,
    29→  WithdrawalRequestEntity,
    30→  WithdrawalRequestStatus,
    31→} from '@/db/entities/withdrawal-request.entity';
    32→
    33→interface CreateWithdrawalRequestData {
    34→  stripeMethodId: string;
    35→}
    36→
    37→interface CreateCryptoWithdrawalRequestData {
    38→  cryptoPaymentMethodId: string;
    39→}
    40→
    41→interface CreatePayPalWithdrawalRequestData {
    42→  paypalMethodId: string;
    43→}
    44→
    45→interface CreateNowPaymentsWithdrawalRequestData {
    46→  cryptoPaymentMethodId: string;
    47→}
    48→
    49→interface AdminWithdrawalRequestFilters {
    50→  status?: WithdrawalRequestStatus;
    51→}
    52→
    53→@Injectable()
    54→export class WithdrawalRequestsService {
    55→  constructor(
    56→    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
    57→    private readonly ledgerService: LedgerService,
    58→    private readonly cryptoAddressesService: CryptoAddressesService,
    59→    private readonly paypalPayoutsService: PaypalPayoutsService,
    60→    private readonly nowpaymentsPayoutsService: NOWPaymentsPayoutsService,
    61→  ) {}
    62→
    63→  /**
    64→   * Create a new withdrawal request for the user.
    65→   *
    66→   * Captures the user's available balance (current balance minus pending withdrawals)
    67→   * and creates a withdrawal request linked to their chosen Stripe payment method.
    68→   * All withdrawals require manual admin approval and processing.
    69→   *
    70→   * @param userId - ID of the user creating the withdrawal request
    71→   * @param data - Withdrawal request data containing stripe method ID
    72→   * @returns Created withdrawal request entity
    73→   *
    74→   * @throws BadRequestException - Invalid stripe method, crypto not supported, etc.
    75→   * @throws NotFoundException - Stripe method not found or doesn't belong to user
    76→   * @throws ConflictException - No available balance (all funds in pending withdrawals)
    77→   */
    78→  async create(
    79→    userId: string,
    80→    data: CreateWithdrawalRequestData,
    81→  ): Promise<WithdrawalRequestEntity> {
    82→    return this.txHost.withTransaction(async () => {
    83→      const withdrawalRequestRepository = this.txHost.tx.getRepository(
    84→        WithdrawalRequestEntity,
    85→      );
    86→      const stripeMethodRepository = this.txHost.tx.getRepository(
    87→        SavedStripeMethodEntity,
    88→      );
    89→      const walletRepository = this.txHost.tx.getRepository(WalletEntity);
    90→      const auditRepository = this.txHost.tx.getRepository(AuditLogEntity);
    91→
    92→      // 1. Validate and get the user's Stripe method
    93→      const stripeMethod = await stripeMethodRepository.findOne({
    94→        where: {
    95→          id: data.stripeMethodId,
    96→        },
    97→        relations: ['wallet'],
    98→        withDeleted: false, // Ensure method is not soft-deleted
    99→      });
   100→
   101→      if (!stripeMethod) {
   102→        throw new NotFoundException(
   103→          'Payment method not found or has been deleted',
   104→        );
   105→      }
   106→
   107→      // 2. Verify the method belongs to the requesting user
   108→      const wallet = await walletRepository.findOne({
   109→        where: { userId },
   110→      });
   111→
   112→      if (!wallet || stripeMethod.walletId !== wallet.id) {
   113→        throw new NotFoundException(
   114→          'Payment method not found or does not belong to you',
   115→        );
   116→      }
   117→
   118→      // 3. Validate method type - only CARD and BANK supported (no crypto)
   119→      if (
   120→        stripeMethod.type !== StripeMethodType.Card &&
   121→        stripeMethod.type !== StripeMethodType.BankAccount
   122→      ) {
   123→        throw new BadRequestException(
   124→          'Unsupported payment method type. Only card and bank account withdrawals are supported.',
   125→        );
   126→      }
   127→
   128→      // 4. Calculate available balance
   129→      const availableBalance =
   130→        await this.ledgerService.getAvailableBalance(userId);
   131→
   132→      if (availableBalance <= 0) {
   133→        throw new ConflictException(
   134→          'No available balance for withdrawal. All funds may already be in pending withdrawal requests.',
   135→        );
   136→      }
   137→
   138→      // 5. Map Stripe method type to withdrawal method type
   139→      const withdrawalMethodType =
   140→        stripeMethod.type === StripeMethodType.Card
   141→          ? WithdrawalMethodType.Card
   142→          : WithdrawalMethodType.Bank;
   143→
   144→      // 6. Create withdrawal request
   145→      const withdrawalRequest = await withdrawalRequestRepository.save({
   146→        userId,
   147→        amount: availableBalance,
   148→        currency: 'USD',
   149→        withdrawalMethodType,
   150→        stripeMethodId: data.stripeMethodId,
   151→        status: WithdrawalRequestStatus.Pending,
   152→        requestedAt: new Date(),
   153→      });
   154→
   155→      // 7. Log audit event
   156→      await auditRepository.save({
   157→        actorUserId: userId,
   158→        entity: 'WithdrawalRequest',
   159→        entityId: withdrawalRequest.id,
   160→        action: 'WITHDRAWAL_REQUEST_CREATED',
   161→        metadata: {
   162→          amount: availableBalance,
   163→          withdrawalMethodType,
   164→          stripeMethodId: data.stripeMethodId,
   165→          stripeMethodLast4: stripeMethod.last4,
   166→          stripeMethodBrand: stripeMethod.brand,
   167→        },
   168→      });
   169→
   170→      // Load the entity with relations for response
   171→      const fullEntity = await withdrawalRequestRepository.findOne({
   172→        where: { id: withdrawalRequest.id },
   173→        relations: ['stripeMethod'],
   174→      });
   175→
   176→      if (!fullEntity) {
   177→        throw new Error('Failed to load created withdrawal request');
   178→      }
   179→
   180→      return fullEntity;
   181→    });
   182→  }
   183→
   184→  /**
   185→   * Create a new crypto withdrawal request for the user.
   186→   *
   187→   * Captures the user's available balance (current balance minus pending withdrawals)
   188→   * and creates a withdrawal request linked to their chosen cryptocurrency address.
   189→   * All withdrawals require manual admin approval and processing.
   190→   *
   191→   * @param userId - ID of the user creating the withdrawal request
   192→   * @param data - Withdrawal request data containing crypto payment method ID
   193→   * @returns Created withdrawal request entity
   194→   *
   195→   * @throws NotFoundException - Crypto address not found or doesn't belong to user
   196→   * @throws ConflictException - No available balance (all funds in pending withdrawals)
   197→   */
   198→  async createWithCrypto(
   199→    userId: string,
   200→    data: CreateCryptoWithdrawalRequestData,
   201→  ): Promise<WithdrawalRequestEntity> {
   202→    return this.txHost.withTransaction(async () => {
   203→      const withdrawalRequestRepository = this.txHost.tx.getRepository(
   204→        WithdrawalRequestEntity,
   205→      );
   206→      const auditRepository = this.txHost.tx.getRepository(AuditLogEntity);
   207→
   208→      // 1. Validate and get the user's crypto address
   209→      const cryptoAddress = await this.cryptoAddressesService.getOne(
   210→        userId,
   211→        data.cryptoPaymentMethodId,
   212→      );
   213→
   214→      // 2. Calculate available balance
   215→      const availableBalance =
   216→        await this.ledgerService.getAvailableBalance(userId);
   217→
   218→      if (availableBalance <= 0) {
   219→        throw new ConflictException(
   220→          'No available balance for withdrawal. All funds may already be in pending withdrawal requests.',
   221→        );
   222→      }
   223→
   224→      // 3. Create withdrawal request
   225→      const withdrawalRequest = await withdrawalRequestRepository.save({
   226→        userId,
   227→        amount: availableBalance,
   228→        currency: 'USD',
   229→        withdrawalMethodType: WithdrawalMethodType.Crypto,
   230→        cryptoPaymentMethodId: data.cryptoPaymentMethodId,
   231→        stripeMethodId: null,
   232→        status: WithdrawalRequestStatus.Pending,
   233→        requestedAt: new Date(),
   234→      });
   235→
   236→      // 4. Log audit event
   237→      await auditRepository.save({
   238→        actorUserId: userId,
   239→        entity: 'WithdrawalRequest',
   240→        entityId: withdrawalRequest.id,
   241→        action: 'WITHDRAWAL_REQUEST_CREATED',
   242→        metadata: {
   243→          amount: availableBalance,
   244→          withdrawalMethodType: WithdrawalMethodType.Crypto,
   245→          cryptoPaymentMethodId: data.cryptoPaymentMethodId,
   246→          cryptoNetwork: cryptoAddress.network,
   247→          cryptoAddress: cryptoAddress.address,
   248→          cryptoLabel: cryptoAddress.label,
   249→        },
   250→      });
   251→
   252→      // Load the entity with relations for response
   253→      const fullEntity = await withdrawalRequestRepository.findOne({
   254→        where: { id: withdrawalRequest.id },
   255→        relations: ['cryptoPaymentMethod'],
   256→      });
   257→
   258→      if (!fullEntity) {
   259→        throw new Error('Failed to load created withdrawal request');
   260→      }
   261→
   262→      return fullEntity;
   263→    });
   264→  }
   265→
   266→  /**
   267→   * Create a new PayPal withdrawal request for the user.
   268→   *
   269→   * Captures the user's available balance (current balance minus pending withdrawals)
   270→   * and creates a withdrawal request linked to their chosen PayPal payment method.
   271→   * All withdrawals require manual admin approval and processing.
   272→   *
   273→   * @param userId - ID of the user creating the withdrawal request
   274→   * @param data - Withdrawal request data containing PayPal method ID
   275→   * @returns Created withdrawal request entity
   276→   *
   277→   * @throws NotFoundException - PayPal method not found or doesn't belong to user
