   313→
   314→      if (!wallet || paypalMethod.walletId !== wallet.id) {
   315→        throw new NotFoundException(
   316→          'PayPal method not found or does not belong to you',
   317→        );
   318→      }
   319→
   320→      // 3. Calculate available balance
   321→      const availableBalance =
   322→        await this.ledgerService.getAvailableBalance(userId);
   323→
   324→      if (availableBalance <= 0) {
   325→        throw new ConflictException(
   326→          'No available balance for withdrawal. All funds may already be in pending withdrawal requests.',
   327→        );
   328→      }
   329→
   330→      // 4. Create withdrawal request
   331→      const withdrawalRequest = await withdrawalRequestRepository.save({
   332→        userId,
   333→        amount: availableBalance,
   334→        currency: 'USD',
   335→        withdrawalMethodType: WithdrawalMethodType.PayPal,
   336→        paypalMethodId: data.paypalMethodId,
   337→        stripeMethodId: null,
   338→        cryptoPaymentMethodId: null,
   339→        status: WithdrawalRequestStatus.Pending,
   340→        requestedAt: new Date(),
   341→      });
   342→
   343→      // 5. Log audit event
   344→      await auditRepository.save({
   345→        actorUserId: userId,
   346→        entity: 'WithdrawalRequest',
   347→        entityId: withdrawalRequest.id,
   348→        action: 'WITHDRAWAL_REQUEST_CREATED',
   349→        metadata: {
   350→          amount: availableBalance,
   351→          withdrawalMethodType: WithdrawalMethodType.PayPal,
   352→          paypalMethodId: data.paypalMethodId,
   353→          paypalMethodEmail: paypalMethod.email,
   354→          paypalMethodType: paypalMethod.type,
   355→          paypalMethodNickname: paypalMethod.nickname,
   356→        },
   357→      });
   358→
   359→      // Load the entity with relations for response
   360→      const fullEntity = await withdrawalRequestRepository.findOne({
   361→        where: { id: withdrawalRequest.id },
   362→        relations: ['paypalMethod'],
