   371→  }
   372→
   373→  /**
   374→   * Create a new Now Payments withdrawal request for the user.
   375→   *
   376→   * Captures the user's available balance (current balance minus pending withdrawals)
   377→   * and creates a withdrawal request linked to their chosen cryptocurrency wallet address.
   378→   * Withdrawal will be processed via Now Payments service.
   379→   * All withdrawals require manual admin approval and processing.
   380→   *
   381→   * @param userId - ID of the user creating the withdrawal request
   382→   * @param data - Withdrawal request data containing crypto payment method ID
   383→   * @returns Created withdrawal request entity
   384→   *
   385→   * @throws NotFoundException - Crypto address not found or doesn't belong to user
   386→   * @throws ConflictException - No available balance (all funds in pending withdrawals)
   387→   */
   388→  async createWithNowPayments(
   389→    userId: string,
   390→    data: CreateNowPaymentsWithdrawalRequestData,
   391→  ): Promise<WithdrawalRequestEntity> {
   392→    return this.txHost.withTransaction(async () => {
   393→      const withdrawalRequestRepository = this.txHost.tx.getRepository(
   394→        WithdrawalRequestEntity,
   395→      );
   396→      const auditRepository = this.txHost.tx.getRepository(AuditLogEntity);
   397→
   398→      // 1. Validate and get the user's crypto address
   399→      const cryptoAddress = await this.cryptoAddressesService.getOne(
   400→        userId,
   401→        data.cryptoPaymentMethodId,
   402→      );
   403→
   404→      // 2. Calculate available balance
   405→      const availableBalance =
   406→        await this.ledgerService.getAvailableBalance(userId);
   407→
   408→      if (availableBalance <= 0) {
   409→        throw new ConflictException(
   410→          'No available balance for withdrawal. All funds may already be in pending withdrawal requests.',
   411→        );
   412→      }
   413→
   414→      // 3. Create withdrawal request
   415→      const withdrawalRequest = await withdrawalRequestRepository.save({
   416→        userId,
   417→        amount: availableBalance,
   418→        currency: 'USD',
   419→        withdrawalMethodType: WithdrawalMethodType.NowPayments,
   420→        cryptoPaymentMethodId: data.cryptoPaymentMethodId,
   421→        stripeMethodId: null,
   422→        status: WithdrawalRequestStatus.Pending,
   423→        requestedAt: new Date(),
   424→      });
   425→
   426→      // 4. Log audit event
   427→      await auditRepository.save({
   428→        actorUserId: userId,
   429→        entity: 'WithdrawalRequest',
   430→        entityId: withdrawalRequest.id,
   431→        action: 'WITHDRAWAL_REQUEST_CREATED',
   432→        metadata: {
   433→          amount: availableBalance,
   434→          withdrawalMethodType: WithdrawalMethodType.NowPayments,
   435→          cryptoPaymentMethodId: data.cryptoPaymentMethodId,
   436→          cryptoNetwork: cryptoAddress.network,
   437→          cryptoAddress: cryptoAddress.address,
   438→          cryptoLabel: cryptoAddress.label,
   439→        },
   440→      });
   441→
   442→      // Load the entity with relations for response
   443→      const fullEntity = await withdrawalRequestRepository.findOne({
   444→        where: { id: withdrawalRequest.id },
   445→        relations: ['cryptoPaymentMethod'],
   446→      });
   447→
   448→      if (!fullEntity) {
   449→        throw new Error('Failed to load created withdrawal request');
   450→      }
   451→
   452→      return fullEntity;
   453→    });
   454→  }
