   480→  /**
   481→   * Get paginated list of all withdrawal requests for admin.
   482→   *
   483→   * @param queryOptions - Pagination and sorting options
   484→   * @param filters - Optional filters (status)
   485→   * @returns Paginated withdrawal requests with user and stripe method relations
   486→   */
   487→  async getManyForAdmin(
   488→    queryOptions: PaginationSortingQuery,
   489→    filters?: AdminWithdrawalRequestFilters,
   490→  ): Promise<PaginatedResponse<WithdrawalRequestEntity>> {
   491→    const withdrawalRequestRepository = this.txHost.tx.getRepository(
   492→      WithdrawalRequestEntity,
   493→    );
   494→
   495→    const query = withdrawalRequestRepository
   496→      .createQueryBuilder('withdrawalRequest')
   497→      .leftJoinAndSelect('withdrawalRequest.user', 'user')
   498→      .leftJoinAndSelect('withdrawalRequest.stripeMethod', 'stripeMethod')
   499→      .leftJoinAndSelect(
   500→        'withdrawalRequest.cryptoPaymentMethod',
   501→        'cryptoPaymentMethod',
   502→      )
   503→      .leftJoinAndSelect('withdrawalRequest.paypalMethod', 'paypalMethod')
   504→      .leftJoinAndSelect(
   505→        'withdrawalRequest.processedByAdmin',
   506→        'processedByAdmin',
   507→      );
   508→
   509→    if (filters?.status) {
   510→      query.andWhere('withdrawalRequest.status = :status', {
   511→        status: filters.status,
   512→      });
   513→    }
   514→
   515→    const [data, total] = await query
   516→      .orderBy('withdrawalRequest.requestedAt', 'DESC')
   517→      .skip(queryOptions.skip)
   518→      .take(queryOptions.take)
   519→      .getManyAndCount();
   520→
   521→    return {
   522→      total,
   523→      data,
   524→      skip: queryOptions.skip,
   525→      take: queryOptions.take,
   526→    };
   527→  }
