   577→  /**
   578→   * Confirm a Stripe withdrawal request by admin with transaction confirmation file.
   579→   *
   580→   * Validates the withdrawal is a Stripe method (CARD/BANK) and requires a file.
   581→   * Updates the withdrawal request to COMPLETED status, posts ledger transaction,
   582→   * and creates audit log entry.
   583→   *
   584→   * @param withdrawalRequestId - ID of the withdrawal request to confirm
   585→   * @param adminId - ID of the admin confirming the withdrawal
   586→   * @param confirmationFileId - ID of the uploaded confirmation file
   587→   * @param confirmationText - Optional confirmation text (should not be provided for Stripe)
   588→   * @returns Updated withdrawal request entity with relations
   589→   *
   590→   * @throws NotFoundException - If withdrawal request or confirmation file not found
   591→   * @throws BadRequestException - If withdrawal request is not Stripe method, status is invalid, or confirmationText is provided
   592→   */
   593→  async confirmStripeWithdrawal(
   594→    withdrawalRequestId: string,
   595→    adminId: string,
   596→    confirmationFileId: string,
   597→    confirmationText?: string,
   598→  ): Promise<WithdrawalRequestEntity> {
   599→    return this.txHost.withTransaction(async () => {
   600→      const withdrawalRequestRepository = this.txHost.tx.getRepository(
   601→        WithdrawalRequestEntity,
   602→      );
   603→      const fileRepository = this.txHost.tx.getRepository(FileEntity);
   604→
   605→      // 1. Load withdrawal request with relations
   606→      const withdrawalRequest = await withdrawalRequestRepository.findOne({
   607→        where: { id: withdrawalRequestId },
   608→        relations: [
   609→          'user',
   610→          'stripeMethod',
   611→          'cryptoPaymentMethod',
   612→          'paypalMethod',
   613→        ],
   614→      });
   615→
   616→      if (!withdrawalRequest) {
   617→        throw new NotFoundException('Withdrawal request not found');
   618→      }
   619→
   620→      // 2. Validate withdrawal method type
   621→      if (
   622→        withdrawalRequest.withdrawalMethodType !== WithdrawalMethodType.Card &&
   623→        withdrawalRequest.withdrawalMethodType !== WithdrawalMethodType.Bank
   624→      ) {
   625→        throw new BadRequestException(
   626→          'This withdrawal request is not a Stripe method. Use the crypto confirmation endpoint instead.',
   627→        );
   628→      }
   629→
   630→      // 3. Validate that confirmation text is not provided for Stripe withdrawals
   631→      if (
   632→        confirmationText !== undefined &&
   633→        confirmationText !== null &&
   634→        typeof confirmationText === 'string' &&
   635→        confirmationText.trim() !== ''
   636→      ) {
   637→        throw new BadRequestException(
   638→          'Confirmation text is not allowed for Stripe withdrawals',
   639→        );
   640→      }
   641→
   642→      // 4. Validate withdrawal request status
   643→      if (
   644→        withdrawalRequest.status !== WithdrawalRequestStatus.Pending &&
   645→        withdrawalRequest.status !== WithdrawalRequestStatus.Approved
   646→      ) {
   647→        throw new BadRequestException(
   648→          `Cannot confirm withdrawal request with status ${withdrawalRequest.status}. Only PENDING or APPROVED requests can be confirmed.`,
   649→        );
   650→      }
   651→
   652→      // 5. Validate confirmation file exists
   653→      const confirmationFile = await fileRepository.findOne({
   654→        where: { id: confirmationFileId },
   655→      });
   656→
   657→      if (!confirmationFile) {
   658→        throw new NotFoundException('Confirmation file not found');
   659→      }
   660→
   661→      // 6. Complete the withdrawal
   662→      return this.completeWithdrawal(
   663→        withdrawalRequest,
   664→        adminId,
   665→        confirmationFileId,
   666→        null,
   667→        withdrawalRequestRepository,
   668→      );
   669→    });
   670→  }
