   672→  /**
   673→   * Confirm a PayPal withdrawal request by admin.
   674→   * Automatically sends funds to user's PayPal account using PayPal Payouts API.
   675→   *
   676→   * Validates the withdrawal is a PayPal method and creates a payout via PayPal.
   677→   * Updates the withdrawal request to COMPLETED status, posts ledger transaction,
   678→   * and creates audit log entry.
   679→   *
   680→   * @param withdrawalRequestId - ID of the withdrawal request to confirm
   681→   * @param adminId - ID of the admin confirming the withdrawal
   682→   * @returns Updated withdrawal request entity with relations
   683→   *
   684→   * @throws NotFoundException - If withdrawal request or PayPal method not found
   685→   * @throws BadRequestException - If withdrawal request is not PayPal method or status is invalid
   686→   */
   687→  async confirmPaypalWithdrawal(
   688→    withdrawalRequestId: string,
   689→    adminId: string,
   690→  ): Promise<WithdrawalRequestEntity> {
   691→    return this.txHost.withTransaction(async () => {
   692→      const withdrawalRequestRepository = this.txHost.tx.getRepository(
   693→        WithdrawalRequestEntity,
   694→      );
   695→      const paypalMethodRepository = this.txHost.tx.getRepository(
   696→        SavedPayPalMethodEntity,
   697→      );
   698→
   699→      // 1. Load withdrawal request with relations
   700→      const withdrawalRequest = await withdrawalRequestRepository.findOne({
   701→        where: { id: withdrawalRequestId },
   702→        relations: ['user', 'paypalMethod'],
   703→      });
   704→
   705→      if (!withdrawalRequest) {
   706→        throw new NotFoundException('Withdrawal request not found');
   707→      }
   708→
   709→      // 2. Validate withdrawal method type
   710→      if (
   711→        withdrawalRequest.withdrawalMethodType !== WithdrawalMethodType.PayPal
   712→      ) {
   713→        throw new BadRequestException(
   714→          'This withdrawal request is not a PayPal method. Use the appropriate confirmation endpoint instead.',
   715→        );
   716→      }
   717→
   718→      // 3. Validate withdrawal request status
   719→      if (
   720→        withdrawalRequest.status !== WithdrawalRequestStatus.Pending &&
   721→        withdrawalRequest.status !== WithdrawalRequestStatus.Approved
   722→      ) {
   723→        throw new BadRequestException(
   724→          `Cannot confirm withdrawal request with status ${withdrawalRequest.status}. Only PENDING or APPROVED requests can be confirmed.`,
   725→        );
   726→      }
   727→
   728→      // 4. Validate PayPal method exists
   729→      if (!withdrawalRequest.paypalMethodId) {
   730→        throw new BadRequestException(
   731→          'PayPal method ID is missing from withdrawal request',
   732→        );
   733→      }
   734→
   735→      const paypalMethod = await paypalMethodRepository.findOne({
   736→        where: { id: withdrawalRequest.paypalMethodId },
   737→      });
   738→
   739→      if (!paypalMethod) {
   740→        throw new NotFoundException('PayPal payment method not found');
   741→      }
   742→
   743→      // 5. Create PayPal payout
   744→      let payoutBatchId: string | null = null;
   745→      let payoutItemId: string | null = null;
   746→
   747→      try {
   748→        const payoutResult = await this.paypalPayoutsService.createPayout(
   749→          withdrawalRequest.amount,
   750→          withdrawalRequest.currency,
   751→          paypalMethod.email,
   752→          `Withdrawal request ${withdrawalRequestId}`,
   753→        );
   754→
   755→        payoutBatchId = payoutResult.payoutBatchId;
   756→        payoutItemId = payoutResult.payoutItemId; // can be null while batch pending
   757→      } catch (error) {
   758→        const err = error as Error;
   759→        throw new BadRequestException(
   760→          `Failed to create PayPal payout: ${err.message}`,
   761→        );
   762→      }
   763→
   764→      // 6. Complete the withdrawal with payout reference
   765→      const withdrawalRequestIdStr = withdrawalRequest.id;
   766→      const auditRepository = this.txHost.tx.getRepository(AuditLogEntity);
   767→
   768→      // Update withdrawal request status
   769→      const now = new Date();
   770→      await withdrawalRequestRepository.save({
   771→        id: withdrawalRequestIdStr,
   772→        status: WithdrawalRequestStatus.Completed,
   773→        processedAt: now,
   774→        processedByAdminId: adminId,
   775→        confirmationText: `PayPal Payout: ${payoutBatchId}${
   776→          payoutItemId ? ` (Item: ${payoutItemId})` : ''
   777→        }`,
   778→      });
   779→
   780→      // Post withdrawal transaction to ledger
   781→      await this.ledgerService.postTransaction({
   782→        type: LedgerTransactionType.WITHDRAWAL,
   783→        currency: withdrawalRequest.currency,
   784→        amountTotal: withdrawalRequest.amount,
   785→        contextRef: `withdrawal:${withdrawalRequestIdStr}:completion`,
   786→        entries: [
   787→          {
   788→            account: AccountType.USER_WALLET,
   789→            direction: EntryDirection.DEBIT,
   790→            amount: withdrawalRequest.amount,
   791→            userId: withdrawalRequest.userId,
   792→          },
   793→          {
   794→            account: AccountType.PLATFORM_CASH,
   795→            direction: EntryDirection.CREDIT,
   796→            amount: withdrawalRequest.amount,
   797→            userId: null,
   798→          },
   799→        ],
   800→      });
   801→
   802→      // Create audit log entry
   803→      await auditRepository.save({
   804→        actorUserId: null, // Admin action
   805→        entity: 'WithdrawalRequest',
   806→        entityId: withdrawalRequestIdStr,
   807→        action: 'WITHDRAWAL_CONFIRMED',
   808→        metadata: {
   809→          adminId,
   810→          amount: withdrawalRequest.amount,
   811→          currency: withdrawalRequest.currency,
   812→          withdrawalMethodType: withdrawalRequest.withdrawalMethodType,
   813→          paypalMethodId: withdrawalRequest.paypalMethodId,
   814→          paypalMethodEmail: paypalMethod.email,
   815→          payoutBatchId,
   816→          payoutItemId,
   817→        },
   818→      });
   819→
   820→      // Return updated entity with relations
   821→      const updatedEntity = await withdrawalRequestRepository.findOne({
   822→        where: { id: withdrawalRequestIdStr },
   823→        relations: [
   824→          'user',
   825→          'paypalMethod',
   826→          'processedByAdmin',
   827→          'confirmationFile',
   828→        ],
   829→      });
   830→
   831→      if (!updatedEntity) {
   832→        throw new Error('Failed to load updated withdrawal request');
   833→      }
   834→
   835→      return updatedEntity;
   836→    });
   837→  }
