   839→  /**
   840→   * Confirm a crypto withdrawal request by admin with transaction confirmation file or text.
   841→   *
   842→   * Validates the withdrawal is a crypto method (CRYPTO) and requires either file or text.
   843→   * Updates the withdrawal request to COMPLETED status, posts ledger transaction,
   844→   * and creates audit log entry.
   845→   *
   846→   * @param withdrawalRequestId - ID of the withdrawal request to confirm
   847→   * @param adminId - ID of the admin confirming the withdrawal
   848→   * @param options - Confirmation options with either confirmationFileId or confirmationText
   849→   * @returns Updated withdrawal request entity with relations
   850→   *
   851→   * @throws NotFoundException - If withdrawal request or confirmation file not found
   852→   * @throws BadRequestException - If withdrawal request is not crypto method, status is invalid, or confirmation validation fails
   853→   */
   854→  async confirmCryptoWithdrawal(
   855→    withdrawalRequestId: string,
   856→    adminId: string,
   857→    options: { confirmationFileId?: string; confirmationText?: string },
   858→  ): Promise<WithdrawalRequestEntity> {
   859→    return this.txHost.withTransaction(async () => {
   860→      const withdrawalRequestRepository = this.txHost.tx.getRepository(
   861→        WithdrawalRequestEntity,
   862→      );
   863→      const fileRepository = this.txHost.tx.getRepository(FileEntity);
   864→
   865→      // 1. Load withdrawal request with relations
   866→      const withdrawalRequest = await withdrawalRequestRepository.findOne({
   867→        where: { id: withdrawalRequestId },
   868→        relations: [
   869→          'user',
   870→          'stripeMethod',
   871→          'cryptoPaymentMethod',
   872→          'paypalMethod',
   873→        ],
   874→      });
   875→
   876→      if (!withdrawalRequest) {
   877→        throw new NotFoundException('Withdrawal request not found');
   878→      }
   879→
   880→      // 2. Validate withdrawal method type (only regular Crypto, not NowPayments)
   881→      if (
   882→        withdrawalRequest.withdrawalMethodType !== WithdrawalMethodType.Crypto
   883→      ) {
   884→        throw new BadRequestException(
   885→          'This withdrawal request is not a regular crypto method. Use the appropriate confirmation endpoint (Stripe, PayPal, or NowPayments).',
   886→        );
   887→      }
   888→
   889→      // 3. Validate withdrawal request status
   890→      if (
   891→        withdrawalRequest.status !== WithdrawalRequestStatus.Pending &&
   892→        withdrawalRequest.status !== WithdrawalRequestStatus.Approved
   893→      ) {
   894→        throw new BadRequestException(
   895→          `Cannot confirm withdrawal request with status ${withdrawalRequest.status}. Only PENDING or APPROVED requests can be confirmed.`,
   896→        );
   897→      }
   898→
   899→      // 4. Validate confirmation (either file OR text, not both)
   900→      const hasFile = !!options.confirmationFileId;
   901→      const hasText = options.confirmationText !== undefined;
   902→
   903→      if (hasFile && hasText) {
   904→        throw new BadRequestException(
   905→          'Cannot provide both confirmation file and text. Please provide either file or text for crypto withdrawals.',
   906→        );
   907→      }
   908→
   909→      if (!hasFile && !hasText) {
   910→        throw new BadRequestException(
   911→          'Either confirmation file or text is required for crypto withdrawals',
   912→        );
   913→      }
   914→
   915→      let confirmationFileId: string | null = null;
   916→      let confirmationText: string | null = null;
   917→
   918→      if (hasFile && options.confirmationFileId !== undefined) {
   919→        const confirmationFile = await fileRepository.findOne({
   920→          where: { id: options.confirmationFileId },
   921→        });
   922→
   923→        if (!confirmationFile) {
   924→          throw new NotFoundException('Confirmation file not found');
   925→        }
   926→
   927→        confirmationFileId = options.confirmationFileId;
   928→      }
   929→
   930→      if (hasText && options.confirmationText !== undefined) {
   931→        const trimmedText = options.confirmationText.trim();
   932→
   933→        if (!trimmedText) {
   934→          throw new BadRequestException('Confirmation text cannot be empty');
   935→        }
   936→
   937→        if (trimmedText.length > 500) {
   938→          throw new BadRequestException(
   939→            'Confirmation text must be 500 characters or less',
   940→          );
   941→        }
   942→
   943→        confirmationText = trimmedText;
   944→      }
   945→
   946→      // 5. Complete the withdrawal
   947→      return this.completeWithdrawal(
   948→        withdrawalRequest,
   949→        adminId,
   950→        confirmationFileId,
   951→        confirmationText,
   952→        withdrawalRequestRepository,
   953→      );
   954→    });
   955→  }
