   957→  /**
   958→   * Common logic for completing a withdrawal request.
   959→   *
   960→   * Updates withdrawal status to COMPLETED, posts ledger transaction,
   961→   * and creates audit log entry.
   962→   *
   963→   * @param withdrawalRequest - The withdrawal request entity
   964→   * @param adminId - ID of the admin confirming the withdrawal
   965→   * @param confirmationFileId - Confirmation file ID (nullable)
   966→   * @param confirmationText - Confirmation text (nullable)
   967→   * @param withdrawalRequestRepository - Repository for withdrawal requests
   968→   * @returns Updated withdrawal request entity with relations
   969→   */
   970→  private async completeWithdrawal(
   971→    withdrawalRequest: WithdrawalRequestEntity,
   972→    adminId: string,
   973→    confirmationFileId: string | null,
   974→    confirmationText: string | null,
   975→    withdrawalRequestRepository: Repository<WithdrawalRequestEntity>,
   976→  ): Promise<WithdrawalRequestEntity> {
   977→    const withdrawalRequestId = withdrawalRequest.id;
   978→    const auditRepository = this.txHost.tx.getRepository(AuditLogEntity);
   979→
   980→    // Update withdrawal request status
   981→    const now = new Date();
   982→    await withdrawalRequestRepository.save({
   983→      id: withdrawalRequestId,
   984→      status: WithdrawalRequestStatus.Completed,
   985→      processedAt: now,
   986→      processedByAdminId: adminId,
   987→      confirmationFileId,
   988→      confirmationText,
   989→    });
   990→
   991→    // Post withdrawal transaction to ledger
   992→    // DEBIT USER_WALLET (reduce user balance)
   993→    // CREDIT PLATFORM_CASH (platform pays out funds)
   994→    await this.ledgerService.postTransaction({
   995→      type: LedgerTransactionType.WITHDRAWAL,
   996→      currency: withdrawalRequest.currency,
   997→      amountTotal: withdrawalRequest.amount,
   998→      contextRef: `withdrawal:${withdrawalRequestId}:completion`,
   999→      entries: [
  1000→        {
  1001→          account: AccountType.USER_WALLET,
  1002→          direction: EntryDirection.DEBIT,
  1003→          amount: withdrawalRequest.amount,
  1004→          userId: withdrawalRequest.userId,
  1005→        },
  1006→        {
  1007→          account: AccountType.PLATFORM_CASH,
  1008→          direction: EntryDirection.CREDIT,
  1009→          amount: withdrawalRequest.amount,
  1010→          userId: null,
  1011→        },
  1012→      ],
  1013→    });
  1014→
  1015→    // Create audit log entry
  1016→    const auditMetadata: Record<string, unknown> = {
  1017→      adminId,
  1018→      amount: withdrawalRequest.amount,
  1019→      currency: withdrawalRequest.currency,
  1020→      confirmationFileId,
  1021→      confirmationText,
  1022→      withdrawalMethodType: withdrawalRequest.withdrawalMethodType,
  1023→    };
  1024→
  1025→    if (withdrawalRequest.stripeMethodId) {
  1026→      auditMetadata.stripeMethodId = withdrawalRequest.stripeMethodId;
  1027→      auditMetadata.stripeMethodLast4 = withdrawalRequest.stripeMethod?.last4;
  1028→      auditMetadata.stripeMethodBrand = withdrawalRequest.stripeMethod?.brand;
  1029→    }
  1030→
  1031→    if (withdrawalRequest.cryptoPaymentMethodId) {
  1032→      auditMetadata.cryptoPaymentMethodId =
  1033→        withdrawalRequest.cryptoPaymentMethodId;
  1034→      auditMetadata.cryptoNetwork =
  1035→        withdrawalRequest.cryptoPaymentMethod?.network;
