     7→/**
     8→ * Service for handling NOWPayments IPN webhook events with idempotency.
     9→ * Stores events in database to prevent duplicate processing.
    10→ */
    11→@Injectable()
    12→export class NOWPaymentsWebhookService {
    13→  private readonly logger = new Logger(NOWPaymentsWebhookService.name);
    14→
    15→  constructor(
    16→    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
    17→  ) {}
    18→
    19→  /**
    20→   * Store a NOWPayments webhook event in the database for idempotency.
    21→   * Returns true if this is a new event, false if already processed.
    22→   *
    23→   * @param paymentId - NOWPayments payment ID (unique identifier)
    24→   * @param eventType - Event type (e.g., 'payment.confirmed', 'payment.finished')
    25→   * @param payload - Complete webhook payload
    26→   * @returns true if event is new (should be processed), false if already seen
    27→   */
    28→  async storeEvent(
    29→    paymentId: number,
    30→    eventType: string,
    31→    payload: Record<string, unknown>,
    32→  ): Promise<boolean> {
    33→    return this.txHost.withTransaction(async () => {
    34→      const repository = this.txHost.tx.getRepository(NOWPaymentsEventEntity);
    35→
    36→      const existingEvent = await repository.findOne({
    37→        where: {
    38→          nowpaymentsPaymentId: paymentId,
    39→          eventType,
    40→        },
    41→      });
    42→
    43→      if (existingEvent) {
    44→        this.logger.log(
    45→          `Event ${paymentId}/${eventType} already processed at ${existingEvent.processedAt?.toISOString() || 'unknown'}`,
    46→        );
    47→
    48→        return false;
    49→      }
    50→
    51→      try {
    52→        await repository.save({
    53→          nowpaymentsPaymentId: paymentId,
    54→          eventType,
    55→          payload,
    56→          processedAt: null,
    57→        });
    58→      } catch (error) {
    59→        if (
    60→          error instanceof Error &&
    61→          error.message.includes('duplicate key value')
    62→        ) {
    63→          this.logger.log(
    64→            `Event ${paymentId}/${eventType} already stored (concurrent insert), skipping`,
    65→          );
    66→          return false;
    67→        }
    68→        throw error;
    69→      }
    70→
    71→      this.logger.log(`Stored new webhook event: ${paymentId} (${eventType})`);
    72→      return true;
    73→    });
    74→  }
    75→
    76→  /**
    77→   * Mark a webhook event as successfully processed.
    78→   *
    79→   * @param paymentId - NOWPayments payment ID
    80→   * @param eventType - Event type
    81→   */
    82→  async markEventProcessed(
    83→    paymentId: number,
    84→    eventType: string,
    85→  ): Promise<void> {
    86→    return this.txHost.withTransaction(async () => {
    87→      const repository = this.txHost.tx.getRepository(NOWPaymentsEventEntity);
    88→
    89→      await repository.update(
    90→        {
    91→          nowpaymentsPaymentId: paymentId,
    92→          eventType,
    93→        },
    94→        { processedAt: new Date() },
    95→      );
    96→
    97→      this.logger.log(`Marked event as processed: ${paymentId}/${eventType}`);
    98→    });
    99→  }
   100→
