   481→      );
   482→      return;
   483→    }
   484→
   485→    if (
   486→      payment.status === PaymentStatus.Created ||
   487→      (payment.status === PaymentStatus.Pending &&
   488→        targetStatus === PaymentStatus.Succeeded)
   489→    ) {
   490→      payment.status = targetStatus;
   491→      payment.metadata = {
   492→        ...payment.metadata,
   493→        nowpaymentsStatus: payload.payment_status,
   494→        confirmations: payload.confirmations,
   495→        lastUpdate: new Date().toISOString(),
   496→      };
   497→      await paymentRepository.save(payment);
