   508→  private async processPayoutStatusChange(
   509→    payoutId: number,
   510→    payoutStatus: string,
   511→    payload: NOWPaymentsPayoutWebhookPayload,
   512→  ): Promise<void> {
   513→    this.logger.log(
   514→      `Processing payout ${payoutId} status change: ${payoutStatus}`,
   515→    );
   516→
   517→    try {
   518→      const normalizedStatus = payoutStatus.toLowerCase();
   519→
   520→      switch (normalizedStatus) {
   521→        case 'created':
   522→        case 'creating':
   523→          await this.handlePayoutCreated(payoutId, payload);
   524→          break;
   525→
   526→        case 'processing':
   527→          await this.handlePayoutProcessing(payoutId, payload);
   528→          break;
   529→
   530→        case 'sent':
   531→          await this.handlePayoutSent(payoutId, payload);
   532→          break;
   533→
   534→        case 'completed':
   535→        case 'finished':
   536→          await this.handlePayoutCompleted(payoutId, payload);
   537→          break;
   538→
   539→        case 'failed':
   540→          await this.handlePayoutFailed(payoutId, payload);
   541→          break;
   542→
   543→        default:
   544→          this.logger.log(
   545→            `Unhandled payout status: ${payoutStatus} for payout ${payoutId}`,
   546→          );
   547→      }
   548→
   549→      this.logger.log(
   550→        `✓ Successfully processed: payout ${payoutId} - ${payoutStatus}`,
   551→      );
   552→    } catch (error) {
   553→      const err = error as Error;
   554→      this.logger.error(
   555→        `✗ Error processing payout ${payoutId} status ${payoutStatus}: ${err.message}`,
   556→        err.stack,
   557→      );
   558→      throw error;
   559→    }
   560→  }
